import{_ as a,o as t,c as i,a2 as r}from"./chunks/framework.B72_uj9U.js";const u=JSON.parse('{"title":"Chapter 9: Terminal User Interfaces","description":"Building rich terminal user interfaces with Ratatui, from ANSI fundamentals to the Elm architecture, custom widgets, and accessible design.","frontmatter":{"title":"Chapter 9: Terminal User Interfaces","description":"Building rich terminal user interfaces with Ratatui, from ANSI fundamentals to the Elm architecture, custom widgets, and accessible design."},"headers":[],"relativePath":"learn/linear/09-terminal-user-interfaces/index.md","filePath":"learn/linear/09-terminal-user-interfaces/index.md"}'),n={name:"learn/linear/09-terminal-user-interfaces/index.md"};function s(l,e,o,c,m,h){return t(),i("div",null,[...e[0]||(e[0]=[r('<h1 id="terminal-user-interfaces" tabindex="-1">Terminal User Interfaces <a class="header-anchor" href="#terminal-user-interfaces" aria-label="Permalink to &quot;Terminal User Interfaces&quot;">​</a></h1><p>This chapter covers the art and engineering of building rich, interactive terminal user interfaces. While web and desktop UIs get most of the attention, terminal UIs occupy a unique niche for developer tools: they work over SSH, inside tmux, on remote servers, and in CI environments. For a coding agent, the terminal is the natural habitat, and a well-crafted TUI can provide an experience that rivals graphical interfaces.</p><p>We start with the fundamentals: the history of terminals from hardware teletypes to modern GPU-accelerated emulators, ANSI escape sequences that control cursor position and text styling, and the critical distinction between raw and cooked input modes. Understanding these foundations will help you debug issues that arise when your TUI misbehaves in certain terminals or over certain connections.</p><p>The bulk of the chapter focuses on Ratatui, the leading Rust TUI framework. You will learn its architecture — the Elm-inspired model-view-update pattern — and how to compose complex interfaces from widgets, layout constraints, and event handlers. We cover building custom widgets for agent-specific needs like streaming markdown rendering, syntax-highlighted code blocks, and tool execution panels. The chapter closes with often-neglected but critical topics: accessibility for screen readers and performance optimization for smooth 60fps rendering.</p><h2 id="learning-objectives" tabindex="-1">Learning Objectives <a class="header-anchor" href="#learning-objectives" aria-label="Permalink to &quot;Learning Objectives&quot;">​</a></h2><ul><li>Understand terminal fundamentals from ANSI escape codes to raw mode and alternate screen buffers</li><li>Apply the Elm architecture (model-view-update) pattern to structure TUI applications</li><li>Build layouts with Ratatui&#39;s constraint-based layout engine for responsive terminal interfaces</li><li>Create custom widgets for agent-specific UI components like streaming text and tool panels</li><li>Implement keyboard event handling with support for key chords, mouse events, and paste detection</li><li>Address accessibility and performance concerns in terminal applications</li></ul><h2 id="subchapters" tabindex="-1">Subchapters <a class="header-anchor" href="#subchapters" aria-label="Permalink to &quot;Subchapters&quot;">​</a></h2><ol><li><a href="/linear/09-terminal-user-interfaces/01-terminal-history.html">Terminal History</a></li><li><a href="/linear/09-terminal-user-interfaces/02-terminal-emulators.html">Terminal Emulators</a></li><li><a href="/linear/09-terminal-user-interfaces/03-ansi-escape-sequences.html">ANSI Escape Sequences</a></li><li><a href="/linear/09-terminal-user-interfaces/04-raw-vs-cooked-mode.html">Raw vs Cooked Mode</a></li><li><a href="/linear/09-terminal-user-interfaces/05-tui-frameworks-landscape.html">TUI Frameworks Landscape</a></li><li><a href="/linear/09-terminal-user-interfaces/06-ratatui-architecture.html">Ratatui Architecture</a></li><li><a href="/linear/09-terminal-user-interfaces/07-the-elm-architecture.html">The Elm Architecture</a></li><li><a href="/linear/09-terminal-user-interfaces/08-widget-system.html">Widget System</a></li><li><a href="/linear/09-terminal-user-interfaces/09-layout-engine.html">Layout Engine</a></li><li><a href="/linear/09-terminal-user-interfaces/10-event-handling.html">Event Handling</a></li><li><a href="/linear/09-terminal-user-interfaces/11-custom-widgets.html">Custom Widgets</a></li><li><a href="/linear/09-terminal-user-interfaces/12-text-input.html">Text Input</a></li><li><a href="/linear/09-terminal-user-interfaces/13-syntax-highlighting-in-terminal.html">Syntax Highlighting in Terminal</a></li><li><a href="/linear/09-terminal-user-interfaces/14-accessibility.html">Accessibility</a></li><li><a href="/linear/09-terminal-user-interfaces/15-performance-rendering.html">Performance Rendering</a></li><li><a href="/linear/09-terminal-user-interfaces/16-summary.html">Summary</a></li></ol><h2 id="prerequisites" tabindex="-1">Prerequisites <a class="header-anchor" href="#prerequisites" aria-label="Permalink to &quot;Prerequisites&quot;">​</a></h2><ul><li>Chapter 8 (streaming and real-time data handling for driving live terminal displays)</li></ul>',10)])])}const f=a(n,[["render",s]]);export{u as __pageData,f as default};
